mapper.select:
SELECT BANNER_ID, BANNER_NM, LINK_URL, BANNER_IMAGE, BANNER_IMAGE_FILE, BANNER_DC, SORT_ORDR, REFLCT_AT, FRST_REGISTER_ID, DATE_FORMAT(FRST_REGIST_PNTTM, '%Y-%m-%d') as FRST_REGIST_PNTTM FROM LETTNBANNER WHERE 1=1
AND BANNER_NM LIKE CONCAT('%', #{searchKeyword}, '%')
ORDER BY FRST_REGIST_PNTTM DESC LIMIT #{recordCountPerPage} OFFSET #{firstIndex}

